const body = $json.body || {};

const rawResult = String(body.result || body.status || body.buildResult || 'UNKNOWN').toUpperCase();
const result = ['SUCCESS', 'FAILURE', 'UNSTABLE', 'ABORTED', 'NOT_BUILT'].includes(rawResult)
  ? rawResult
  : 'UNKNOWN';

const service = String(body.service || body.component || 'unknown');
const environment = String(body.environment || body.env || 'unknown');
const jobName = String(body.jobName || body.job_name || body.pipeline || 'unknown-job');
const buildNumber = String(body.buildNumber || body.build_number || body.number || '');
const buildUrl = String(body.buildUrl || body.build_url || body.url || '');
const branch = String(body.branch || body.gitBranch || body.branchName || '');
const releaseTag = String(body.releaseTag || body.release_tag || body.version || '');
const image = String(body.image || body.imageTag || body.image_tag || '');
const targetColor = String(body.targetColor || body.target_color || '');
const activeColor = String(body.activeColor || body.active_color || '');
const failedStage = String(body.failedStage || body.failed_stage || body.stage || '');
const triggeredBy = String(body.triggeredBy || body.triggered_by || '');
const message = String(body.message || '');
const finishedAt = String(body.finishedAt || body.finished_at || new Date().toISOString());

const statusMap = {
  SUCCESS: { emoji: ':shark_no2:', label: '배포 성공' },
  FAILURE: { emoji: ':shark_exclamation_mark:', label: '배포 실패' },
  UNSTABLE: { emoji: ':shark_confuse:', label: '배포 불안정' },
  ABORTED: { emoji: ':shark_exclamation_mark:', label: '배포 중단' },
  NOT_BUILT: { emoji: ':shark_dotdotdot:', label: '배포 스킵' },
  UNKNOWN: { emoji: ':shark_question_mark:', label: '배포 상태 미확인' }
};

const meta = statusMap[result] || statusMap.UNKNOWN;
const serviceLabel = service.toUpperCase();
const environmentLabel = environment.toUpperCase();

const lines = [
  `### ${meta.emoji} [${serviceLabel}][${environmentLabel}][${result}]`,
  `**잡**: ${jobName}${buildNumber ? ` #${buildNumber}` : ''}`
];

if (branch) lines.push(`**브랜치**: \`${branch}\``);
if (releaseTag) lines.push(`**릴리즈 태그**: \`${releaseTag}\``);
if (image) lines.push(`**이미지**: \`${image}\``);
if (targetColor) lines.push(`**배포 색상**: \`${targetColor}\``);
if (activeColor) lines.push(`**현재 활성 색상**: \`${activeColor}\``);
if (failedStage) lines.push(`**실패 단계**: ${failedStage}`);
if (triggeredBy) lines.push(`**실행자**: ${triggeredBy}`);
if (finishedAt) lines.push(`**완료 시각**: \`${finishedAt}\``);
if (message) lines.push(`**메시지**: ${message}`);
if (buildUrl) lines.push(`[Jenkins 빌드 열기](${buildUrl})`);

return {
  json: {
    result,
    service,
    environment,
    jobName,
    buildNumber,
    buildUrl,
    branch,
    releaseTag,
    image,
    targetColor,
    activeColor,
    failedStage,
    triggeredBy,
    finishedAt,
    message,
    mattermostText: lines.join('\n')
  }
};
